-- Run the whole file in a Workspace SQL worksheet (Run All). No CLI / PUT / Python.
-- Synthetic demo data (seed=42, today=2026-06-22); chat tables stay empty.
-- Prereq: GRANT DATABASE ROLE SNOWFLAKE.CORTEX_USER TO ROLE SYSADMIN;

-- 1) Warehouse + database + schema
USE ROLE SYSADMIN;
CREATE WAREHOUSE IF NOT EXISTS DEMO_WH
    WAREHOUSE_SIZE = XSMALL AUTO_SUSPEND = 60 AUTO_RESUME = TRUE INITIALLY_SUSPENDED = TRUE;
CREATE DATABASE IF NOT EXISTS DEMO_DYNAMICS_APP COMMENT = 'Cortex Dashboard Kit demo — synthetic data';
CREATE SCHEMA IF NOT EXISTS DEMO_DYNAMICS_APP.PUBLIC;
USE SCHEMA DEMO_DYNAMICS_APP.PUBLIC;
USE WAREHOUSE DEMO_WH;

-- 2) Tables

CREATE OR REPLACE TABLE CUSTOMERS (  -- one row per customer account
    CUSTOMER_ID NUMBER PRIMARY KEY,
    CUSTOMER_NUMBER VARCHAR(20),
    DISPLAY_NAME VARCHAR(150),
    ADDRESS_COUNTRY VARCHAR(60),
    CUSTOMER_TYPE VARCHAR(20),
    CREDIT_LIMIT NUMBER,
    BALANCE_DUE FLOAT
);
CREATE OR REPLACE TABLE PRODUCTS (  -- one row per item
    PRODUCT_ID NUMBER PRIMARY KEY,
    ITEM_NUMBER VARCHAR(20),
    DISPLAY_NAME VARCHAR(120),
    CATEGORY VARCHAR(40),
    UNIT_PRICE FLOAT,
    UNIT_COST FLOAT,
    INVENTORY NUMBER
);
CREATE OR REPLACE TABLE VENDORS (  -- one row per vendor
    VENDOR_ID NUMBER PRIMARY KEY,
    VENDOR_NUMBER VARCHAR(20),
    DISPLAY_NAME VARCHAR(150),
    COUNTRY VARCHAR(60),
    BALANCE FLOAT
);
CREATE OR REPLACE TABLE SALES_ORDERS (  -- one row per sales order header
    ORDER_ID NUMBER PRIMARY KEY,
    ORDER_NUMBER VARCHAR(20),
    ORDER_DATE DATE,
    CUSTOMER_ID NUMBER,
    STATUS VARCHAR(20),
    CURRENCY_CODE VARCHAR(10),
    TOTAL_EXCL_TAX FLOAT,
    TOTAL_INCL_TAX FLOAT
);
CREATE OR REPLACE TABLE SALES_ORDER_LINES (  -- one row per sales order line (child of SALES_ORDERS)
    LINE_ID NUMBER PRIMARY KEY,
    ORDER_ID NUMBER,
    LINE_TYPE VARCHAR(20),
    PRODUCT_ID NUMBER,
    QUANTITY NUMBER,
    UNIT_PRICE FLOAT,
    LINE_AMOUNT FLOAT
);
CREATE OR REPLACE TABLE INVOICES (  -- one row per sales invoice
    INVOICE_ID NUMBER PRIMARY KEY,
    INVOICE_NUMBER VARCHAR(20),
    CUSTOMER_ID NUMBER,
    INVOICE_DATE DATE,
    DUE_DATE DATE,
    TOTAL_AMOUNT FLOAT,
    STATUS VARCHAR(20)
);
CREATE OR REPLACE TABLE GL_ENTRIES (  -- one row per general-ledger entry
    ENTRY_ID NUMBER PRIMARY KEY,
    POSTING_DATE DATE,
    ACCOUNT_NUMBER VARCHAR(20),
    ACCOUNT_NAME VARCHAR(60),
    DEBIT_AMOUNT FLOAT,
    CREDIT_AMOUNT FLOAT,
    DOCUMENT_TYPE VARCHAR(20)
);
CREATE OR REPLACE TABLE COMPANY_KNOWLEDGE_BASE (  -- one row per knowledge-base document
    DOC_ID NUMBER PRIMARY KEY,
    TITLE VARCHAR(200),
    CATEGORY VARCHAR(80),
    AUDIENCE VARCHAR(40),
    CONTENT VARCHAR
);
CREATE OR REPLACE TABLE CHAT_SESSIONS (  -- one row per chat conversation (written by the app)
    SESSION_ID NUMBER AUTOINCREMENT PRIMARY KEY,
    USERNAME VARCHAR(150),
    SESSION_NAME VARCHAR(200),
    CREATED_AT TIMESTAMP_NTZ DEFAULT CURRENT_TIMESTAMP(),
    LAST_ACTIVE TIMESTAMP_NTZ DEFAULT CURRENT_TIMESTAMP()
);
CREATE OR REPLACE TABLE CHAT_MESSAGES (  -- one row per chat message (written by the app)
    MESSAGE_ID NUMBER AUTOINCREMENT PRIMARY KEY,
    SESSION_ID NUMBER,
    USERNAME VARCHAR(150),
    ROLE VARCHAR(20),
    CONTENT VARCHAR,
    SOURCES VARCHAR,
    CREATED_AT TIMESTAMP_NTZ DEFAULT CURRENT_TIMESTAMP()
);

-- 3) Seed data (synthetic; INSERTed inline so no stage/PUT is needed)
-- CUSTOMERS — one row per customer account

-- PRODUCTS — one row per item

-- VENDORS — one row per vendor

-- SALES_ORDERS — one row per sales order header

-- SALES_ORDER_LINES — one row per sales order line (child of SALES_ORDERS)

-- INVOICES — one row per sales invoice

-- GL_ENTRIES — one row per general-ledger entry

-- COMPANY_KNOWLEDGE_BASE — one row per knowledge-base document

-- 4) Cortex Search service for the RAG knowledge base
USE SCHEMA DEMO_DYNAMICS_APP.PUBLIC;
USE WAREHOUSE DEMO_WH;

CREATE OR REPLACE CORTEX SEARCH SERVICE COMPANY_KB_SEARCH
    ON CONTENT
    ATTRIBUTES CATEGORY, TITLE, AUDIENCE
    WAREHOUSE = DEMO_WH
    TARGET_LAG = '1 hour'
    EMBEDDING_MODEL = 'snowflake-arctic-embed-m-v1.5'
    AS SELECT CONTENT, CATEGORY, TITLE, AUDIENCE FROM DEMO_DYNAMICS_APP.PUBLIC.COMPANY_KNOWLEDGE_BASE;

-- 5) Verification — every data table should be non-empty
SELECT * FROM (
    SELECT 'CUSTOMERS' AS TBL, COUNT(*) AS N FROM CUSTOMERS
    UNION ALL SELECT 'PRODUCTS' AS TBL, COUNT(*) AS N FROM PRODUCTS
    UNION ALL SELECT 'VENDORS' AS TBL, COUNT(*) AS N FROM VENDORS
    UNION ALL SELECT 'SALES_ORDERS' AS TBL, COUNT(*) AS N FROM SALES_ORDERS
    UNION ALL SELECT 'SALES_ORDER_LINES' AS TBL, COUNT(*) AS N FROM SALES_ORDER_LINES
    UNION ALL SELECT 'INVOICES' AS TBL, COUNT(*) AS N FROM INVOICES
    UNION ALL SELECT 'GL_ENTRIES' AS TBL, COUNT(*) AS N FROM GL_ENTRIES
    UNION ALL SELECT 'COMPANY_KNOWLEDGE_BASE' AS TBL, COUNT(*) AS N FROM COMPANY_KNOWLEDGE_BASE
) ORDER BY N ASC, TBL;

